+export function shouldSyncReviewComment(options: {
+  syncCommentsOnly: boolean;
+  isCloseProposal: boolean;
+  commentSyncMinAgeDays: number;
+  reviewCommentSyncedAt: string | undefined;
+  hasExistingReviewComment: boolean;
